display.text:
fn build_value_items(
    values: &[schema::ValueSuggestion],
    replace_range: Range,
) -> Vec<CompletionItem> {
    let text_edit = |new_text: String| -> Option<CompletionTextEdit> {
        Some(CompletionTextEdit::Edit(TextEdit {
            range: replace_range,
            new_text,
        }))
    };

    values
        .iter()
        .flat_map(|v| match v {
            schema::ValueSuggestion::Enum(val) => {
                let formatted = format_json_value(val);
                vec![CompletionItem {
                    label: formatted.clone(),
                    kind: Some(CompletionItemKind::ENUM_MEMBER),
                    text_edit: text_edit(formatted),
                    ..Default::default()
                }]
            }
            schema::ValueSuggestion::Const(val) => {
                let formatted = format_json_value(val);
                vec![CompletionItem {
                    label: formatted.clone(),
                    kind: Some(CompletionItemKind::VALUE),
                    text_edit: text_edit(formatted),
                    ..Default::default()
                }]
            }
            schema::ValueSuggestion::Boolean => {
                vec![
                    CompletionItem {
                        label: "true".to_string(),
                        kind: Some(CompletionItemKind::VALUE),
                        text_edit: text_edit("true".to_string()),
                        ..Default::default()
                    },
                    CompletionItem {
                        label: "false".to_string(),
                        kind: Some(CompletionItemKind::VALUE),
                        text_edit: text_edit("false".to_string()),
                        ..Default::default()
                    },
                ]
            }
            schema::ValueSuggestion::Null => {
                vec![CompletionItem {
                    label: "null".to_string(),
                    kind: Some(CompletionItemKind::VALUE),
                    text_edit: text_edit("null".to_string()),
                    ..Default::default()
                }]
            }
        })
        .collect()
}

/// Format a serde_json::Value as a JSON string suitable for insertion.
fn format_json_value(value: &serde_json::Value) -> String {
    serde_json::to_string(value).unwrap_or_default()
}

/// Return a snippet placeholder appropriate for the given JSON schema type.
fn snippet_for_type(schema_type: Option<&str>) -> &'static str {
    match schema_type {
        Some("string") => "\"$1\"",
        Some("number") | Some("integer") => "${1:0}",
        Some("boolean") => "${1:false}",
        Some("object") => "{$1}",
        Some("array") => "[$1]",
        Some("null") => "null",
        _ => "$0",
    }
}

/// Start the LSP server over stdio.
pub async fn run_server() {
    let stdin = tokio::io::stdin();
    let stdout = tokio::io::stdout();

    let (service, socket) = LspService::new(Backend::new);
    Server::new(stdin, stdout, socket).serve(service).await;
}

