/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `enum`, `const`, and `type` to generate value suggestions.
///
/// Handles composition keywords (anyOf, oneOf, allOf) by gathering suggestions
/// from all branches. Handles nullable types via array-style `type` (e.g.
/// `["string", "null"]`) and the `nullable: true` flag.
///
/// Deduplicates suggestions across branches so that the same value never
/// appears more than once.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut seen: HashSet<serde_json::Value> = HashSet::new();
    let mut suggestions = Vec::new();
    collect_values_from(subschema, &mut seen, &mut suggestions, 0);
    suggestions
}

/// Recursively collect value suggestions from a schema, following composition
/// keywords and handling nullable types.
fn collect_values_from(
    schema: &serde_json::Value,
    seen: &mut HashSet<serde_json::Value>,
    suggestions: &mut Vec<ValueSuggestion>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    // Check for const first (takes priority).
    if let Some(const_val) = schema.get("const") {
        if seen.insert(const_val.clone()) {
            suggestions.push(ValueSuggestion::Const(const_val.clone()));
        }
        return;
    }

    // Check for enum.
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            if seen.insert(val.clone()) {
                suggestions.push(ValueSuggestion::Enum(val.clone()));
            }
        }
        return;
    }

    // Handle nullable via the `nullable: true` flag (Draft 4 compat).
    if schema.get("nullable").and_then(|v| v.as_bool()).unwrap_or(false) {
        if seen.insert(serde_json::json!(null)) {
            suggestions.push(ValueSuggestion::Null);
        }
    }

    // Handle type as a string.
    if let Some(type_str) = schema.get("type").and_then(|v| v.as_str()) {
        match type_str {
            "boolean" => {
                if seen.insert(serde_json::json!(true)) {
                    suggestions.push(ValueSuggestion::Boolean);
                }
            }
            "null" => {
                if seen.insert(serde_json::json!(null)) {
                    suggestions.push(ValueSuggestion::Null);
                }
            }
            _ => {}
        }
    }

    // Handle type as an array (e.g. ["string", "null"] for optional string).
    if let Some(type_arr) = schema.get("type").and_then(|v| v.as_array()) {
        for type_entry in type_arr {
            if let Some(type_str) = type_entry.as_str() {
                match type_str {
                    "boolean" => {
                        if seen.insert(serde_json::json!(true)) {
                            suggestions.push(ValueSuggestion::Boolean);
                        }
                    }
                    "null" => {
                        if seen.insert(serde_json::json!(null)) {
                            suggestions.push(ValueSuggestion::Null);
                        }
                    }
                    _ => {}
                }
            }
        }
    }

    // Recurse into anyOf branches.
    if let Some(any_of) = schema.get("anyOf").and_then(|v| v.as_array()) {
        for branch in any_of {
            let mut branch_visited = HashSet::new();
            let resolved = follow_ref(root, branch, &mut branch_visited);
            if let Some(resolved) = resolved {
                collect_values_from(resolved, seen, suggestions, depth + 1);
            } else {
                collect_values_from(branch, seen, suggestions, depth + 1);
            }
        }
    }

    // Recurse into oneOf branches.
    if let Some(one_of) = schema.get("oneOf").and_then(|v| v.as_array()) {
        for branch in one_of {
            let mut branch_visited = HashSet::new();
            let resolved = follow_ref(root, branch, &mut branch_visited);
            if let Some(resolved) = resolved {
                collect_values_from(resolved, seen, suggestions, depth + 1);
            } else {
                collect_values_from(branch, seen, suggestions, depth + 1);
            }
        }
    }

    // Recurse into allOf branches.
    if let Some(all_of) = schema.get("allOf").and_then(|v| v.as_array()) {
        for branch in all_of {
            let mut branch_visited = HashSet::new();
            let resolved = follow_ref(root, branch, &mut branch_visited);
            if let Some(resolved) = resolved {
                collect_values_from(resolved, seen, suggestions, depth + 1);
            } else {
                collect_values_from(branch, seen, suggestions, depth + 1);
            }
        }
    }
}

