fn build_value_items(
    values: &[schema::ValueSuggestion],
    replace_range: Range,
) -> Vec<CompletionItem> {
    let text_edit = |new_text: String| -> Option<CompletionTextEdit> {
        Some(CompletionTextEdit::Edit(TextEdit {
            range: replace_range,
            new_text,
        }))
    };
    let mut seen_labels: HashSet<String> = HashSet::new();

    values
        .iter()
        .flat_map(|v| match v {
            schema::ValueSuggestion::Enum(val) => {
                let formatted = format_json_value(val);
                vec![CompletionItem {
                    label: formatted.clone(),
                    kind: Some(CompletionItemKind::ENUM_MEMBER),
                    text_edit: text_edit(formatted),
                    ..Default::default()
                }]
            }
            schema::ValueSuggestion::Const(val) => {
                let formatted = format_json_value(val);
                vec![CompletionItem {
                    label: formatted.clone(),
                    kind: Some(CompletionItemKind::VALUE),
                    text_edit: text_edit(formatted),
                    ..Default::default()
                }]
            }
            schema::ValueSuggestion::Boolean => {
                vec![
                    CompletionItem {
                        label: "true".to_string(),
                        kind: Some(CompletionItemKind::VALUE),
                        text_edit: text_edit("true".to_string()),
                        ..Default::default()
                    },
                    CompletionItem {
                        label: "false".to_string(),
                        kind: Some(CompletionItemKind::VALUE),
                        text_edit: text_edit("false".to_string()),
                        ..Default::default()
                    },
                ]
            }
            schema::ValueSuggestion::Null => {
                vec![CompletionItem {
                    label: "null".to_string(),
                    kind: Some(CompletionItemKind::VALUE),
                    text_edit: text_edit("null".to_string()),
                    ..Default::default()
                }]
            }
        })
        .filter(|item| {
            use crate::lsp::CompletionItemKind;
            // Filter: if Boolean or Null were generated from the same subschema
            // node, only keep the first occurrence per kind.
            if item.kind == Some(CompletionItemKind::VALUE) {
                if item.label == "true" || item.label == "false" {
                    let key = format!("bool:{}", item.label);
                    return !seen_labels.contains(&key);
                }
                if item.label == "null" {
                    let key = "null".to_string();
                    return !seen_labels.contains(&key);
                }
                // For enum/const values that happen to be true/false/null,
                // avoid duplicating the standalone Boolean/Null suggestions.
                let key = item.label.clone();
                if seen_labels.contains(&key) {
                    return false;
                }
                seen_labels.insert(key);
                true
            } else {
                let key = format!("enum:{}", item.label);
                return !seen_labels.contains(&key);
            }
        })
        .collect()
}

