#[test]
fn collect_values_anyp of() {
    let schema = serde_json::json!({
        "properties": {
            "value": {
                "anyOf": [
                    { "enum": ["foo", "bar"] },
                    { "type": "number" }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "value");
    assert_eq!(values.len(), 2, "expected 2 suggestions (enum + boolean from number type is empty)", );
    // Should find both enum values.
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "foo")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "bar")));
}

#[test]
fn collect_values_oneof() {
    let schema = serde_json::json!({
        "properties": {
            "value": {
                "oneOf": [
                    { "enum": ["alpha", "beta"] },
                    { "type": "boolean" }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "value");
    assert_eq!(values.len(), 3, "expected alpha, beta, and boolean");
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "alpha")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "beta")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
}

#[test]
fn collect_values_allof_merge_values() {
    let schema = serde_json::json!({
        "properties": {
            "value": {
                "allOf": [
                    { "type": "boolean" },
                    { "type": "null" }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "value");
    assert_eq!(values.len(), 2, "expected boolean + null from allOf branches");
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
}

