            }
        }
    });
    let values = collect_values(&schema, &[], "optional_name");
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
}

#[test]
fn collect_values_nullable_flag() {
    let schema = serde_json::json!({
        "properties": {
            "optional_name": {
                "type": "string",
                "nullable": true
            }
        }
    });
    let values = collect_values(&schema, &[], "optional_name");
