}

#[test]
fn collect_values_anyp of_deduplicate() {
    let schema = serde_json::json!({
        "properties": {
            "value": {
                "anyOf": [
                    { "const": "dedup" },
                    { "const": "dedup" }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "value");
    let count = values.iter().filter(|v| matches!(v, ValueSuggestion::Const(c) if c == "dedup")).count();
    assert_eq!(count, 1, "duplicate const should be deduplicated");
}

#[test]
fn collect_values_anyp of_boolean_deduplicate() {
    let schema = serde_json::json!({
        "properties": {
            "flag": {
                "anyOf": [
                    { "type": "boolean" },
                    { "type": "boolean" }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "flag");
    let bool_count = values.iter().filter(|v| matches!(v, ValueSuggestion::Boolean)).count();
    assert_eq!(bool_count, 1, "duplicate boolean should be deduplicated");
}

#[test]
fn collect_values_anyp of_nullable_mixed() {
    let schema = serde_json::json!({
        "properties": {
            "value": {
                "anyOf": [
                    { "enum": ["on", "off"] },
                    { "type": "null" },
                    { "nullable": true }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "value");
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)), "null should be present");
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "on")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "off")));
    // Both null sources should produce only one null suggestion.
    let null_count = values.iter().filter(|v| matches!(v, ValueSuggestion::Null)).count();
    assert_eq!(null_count, 1, "null should be deduplicated");
}

