                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "value");
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "red")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "blue")));
    assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
}

