/// anyOf with mixed types: string + number + null produces null suggestion.
#[tokio::test]
async fn completion_anyof_mixed_types() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = composed_doc_with_schema(r#""status": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"status\": ").unwrap() + "\"status\": ".len();
    let cursor_col = idx as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    // The anyOf has string, number, and null — only null produces a value suggestion.
    assert!(
        names.contains(&"null".to_string()),
        "expected 'null' from anyOf with null type, got: {names:?}"
    );
}

