/// Duplicate schema types across branches produce no duplicate suggestions.
#[tokio::test]
async fn completion_no_duplicate_boolean_suggestions() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = composed_doc_with_schema(r#""mode": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"mode\": ").unwrap() + "\"mode\": ".len();
    let cursor_col = idx as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let true_count = items
        .iter()
        .filter(|i| i["label"] == "true")
        .count();
    let false_count = items
        .iter()
        .filter(|i| i["label"] == "false")
        .count();
    assert_eq!(true_count, 1, "expected exactly one 'true' suggestion, got {true_count}");
    assert_eq!(false_count, 1, "expected exactly one 'false' suggestion, got {false_count}");
}

/// const takes priority over enum: only const value appears.
#[tokio::test]
async fn completion_const_takes_priority() {
