#[tokio::test]
async fn completion_const_takes_priority() {
    let mut client = TestClient::new();
    client.initialize().await;

    // Use the existing completion-schema.json which has "version": { "const": 2 }
    let content = completion_doc_with_schema(r#""version": 0"#);
    let uri = completion_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"version\": ").unwrap() + "\"version\": ".len();
    let cursor_col = idx as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    assert!(
        names.contains(&r#""2""#.to_string()),
        "expected '2' for const value, got: {names:?}"
    );
    // const should short-circuit, so no other suggestions.
